import './index.less'
import { useEffect, useMemo, useState } from 'react'
import { useTranslation } from 'react-i18next'
import { Button, Divider, Modal, Spin } from '@arco-design/web-react'
import { IconShareExternal } from '@arco-design/web-react/icon'
import { useRequest } from 'ahooks'
import LogoIcon from '@common/assets/images/logo'
import UserHead from '@common/components/UserHead'
import PdfExportIcon from '@/assets/images/icon/pdfExport-icon.svg?react'
import { usePDFExport } from '@/pages/IncidentReport/IncidentReport/hooks/usePDFExport'
import { monthlyInspectionReport } from '@/service/apis'
import {
  INSPECTION_FLOOR_CODES,
  IsSituationEnum,
  approvalResultEnum,
  approveActionTypeEnum,
} from '@/constants/monthlyInspection'
import { handelFieldNameShow } from '@/utils/tools'
import type {
  InspectionReportChecklistGroup,
  InspectionReportResp,
} from '@/types/MonthlyInspection'

const classPrefix = 'inspection-report-export'

// ---------------- 展示映射工具(区域/楼层标签走 i18n,随语言切换) ----------------

type Translator = (key: string, options?: Record<string, unknown>) => string

const AREA_TYPE_LABEL_KEYS: Record<number, string> = {
  1: 'monthlyInspection:form.tabs.around',
  2: 'monthlyInspection:form.tabs.inside',
  3: 'monthlyInspection:form.tabs.parking',
}

const PARKING_FLOOR_LABELS: Record<number, string> = {
  9: 'P1',
  10: 'P2',
  11: 'P3',
}

/** 主 Tab 标签:1 Around / 2 Inside / 3 Parking(en/ar 由 locale 决定) */
const formatAreaLabel = (t: Translator, type?: number | null): string =>
  type != null && AREA_TYPE_LABEL_KEYS[type]
    ? t(AREA_TYPE_LABEL_KEYS[type])
    : ''

/** FloorEnum code → 楼层名:-1 Around 无楼层 / 0-8 G..RF / 9-11 P1..P3 */
const formatFloorLabel = (floorCode?: number | null): string => {
  if (floorCode == null || floorCode < 0) return ''
  if (floorCode <= 8) return INSPECTION_FLOOR_CODES[floorCode] ?? ''
  return PARKING_FLOOR_LABELS[floorCode] ?? ''
}

/** Findings 表 Area & Floor 列:Around the Building / Inside the Building - G */
const formatReportArea = (
  t: Translator,
  type?: number | null,
  floorCode?: number | null,
): string => {
  const area = formatAreaLabel(t, type)
  const floor = formatFloorLabel(floorCode)
  return floor ? `${area} - ${floor}` : area
}

/** Checklist 组标题:AROUND THE BUILDING / INSIDE THE BUILDING - FLOOR G / PARKING - P1 */
const formatChecklistGroupTitle = (
  t: Translator,
  group: InspectionReportChecklistGroup,
): string => {
  const area = formatAreaLabel(t, group.type)
  const floor = formatFloorLabel(group.floorCode)
  if (!floor) return area.toUpperCase()
  const suffix =
    group.type === 2
      ? t('monthlyInspection:form.floor', { code: floor })
      : floor
  return `${area} - ${suffix}`.toUpperCase()
}

const formatDuration = (report?: InspectionReportResp): string => {
  if (!report) return '-'
  const { durationDays, durationHours, durationMinutes } = report
  if (
    durationDays == null &&
    durationHours == null &&
    durationMinutes == null
  ) {
    return '-'
  }
  return `${durationDays ?? 0}d ${durationHours ?? 0}h ${durationMinutes ?? 0}m`
}

/** inspectionDate(dd/MM/yyyy)→ "YYYY / MM" */
const formatInspectionMonth = (inspectionDate?: string | null): string => {
  if (!inspectionDate) return '-'
  const [, month, year] = inspectionDate.split('/')
  return year && month ? `${year} / ${month}` : inspectionDate
}

// ---------------- 组件 ----------------

interface ExportReportModalProps {
  visible: boolean
  inspectionId?: string | number
  onCancel: () => void
}

// html2canvas 的文字基线计算与浏览器不一致,快照中文字会下沉。
// 仅在克隆文档里上移补偿(不影响 Modal 显示)。
// 数值经像素级实测校准:12px 字体在 html2canvas 中固有下沉约 1.1px,
// 补偿 -1px 后偏差 ≈ 0.1px(实测见 e:\hse-workspace\html2canvas-pill-test.html)
const PDF_TOPBAR_TEXT_NUDGE = '-6px'
// 胶囊标签内文字(Yes/No、Approved/Rejected、人名)的快照补偿,只动字不动背景
const PDF_TAG_TEXT_NUDGE = '-6px'

const patchExportReportPdfClone = (clonedDoc: Document) => {
  clonedDoc
    .querySelectorAll<HTMLElement>(`.${classPrefix}__topbar-text`)
    .forEach((el) => {
      el.style.transform = `translateY(${PDF_TOPBAR_TEXT_NUDGE})`
    })

  // 审批时间线的标题/时间与胶囊文字同量级下沉(约 6px),共用 -6px 补偿
  clonedDoc
    .querySelectorAll<HTMLElement>(
      `.${classPrefix}__tag-text, .${classPrefix}__approval-title, .${classPrefix}__approval-time`,
    )
    .forEach((el) => {
      el.style.transform = `translateY(${PDF_TAG_TEXT_NUDGE})`
    })
}

const ExportReportModal = ({
  visible,
  inspectionId,
  onCancel,
}: ExportReportModalProps) => {
  const { t } = useTranslation([
    'monthlyInspection',
    'employeeViolations',
    'common',
  ])
  const [exporting, setExporting] = useState(false)

  const {
    data: report,
    loading: reportLoading,
    run: fetchReport,
  } = useRequest(monthlyInspectionReport, { manual: true })

  useEffect(() => {
    if (visible && inspectionId != null) {
      fetchReport({ inspectionId })
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [visible, inspectionId])

  const { targetRef, exportToPDF } = usePDFExport({
    filename: 'monthly_inspection_report',
    scale: 2,
    orientation: 'p',
    format: 'a4',
    singlePage: true,
    onClone: patchExportReportPdfClone,
  })

  const handleExport = async () => {
    if (exporting) return
    setExporting(true)
    try {
      await exportToPDF()
    } catch (error) {
      console.error('PDF export failed:', error)
    } finally {
      setExporting(false)
    }
  }

  const inspectorsText = useMemo(
    () =>
      (report?.inspectorList ?? [])
        .map((item) =>
          handelFieldNameShow(
            item.inspectorName ?? '',
            item.inspectorNameAr ?? '',
          ),
        )
        .filter(Boolean)
        .join(', ') || '-',
    [report],
  )

  const kpiCards = useMemo(() => {
    const kpi = report?.kpi
    return [
      {
        label: t('monthlyInspection:report.kpi.itemsInspected'),
        value: kpi?.itemsInspected ?? '-',
      },
      {
        label: t('monthlyInspection:report.kpi.compliant'),
        value: kpi?.compliantCount ?? '-',
        tone: 'green',
      },
      {
        label: t('monthlyInspection:report.kpi.nonCompliant'),
        value: kpi?.nonCompliantCount ?? '-',
        tone: 'red',
      },
      {
        label: t('monthlyInspection:report.kpi.complianceRate'),
        value: kpi?.complianceRate != null ? `${kpi.complianceRate}%` : '-',
      },
      {
        label: t('monthlyInspection:report.kpi.issueFindings'),
        value: kpi?.findingCount ?? '-',
      },
      {
        label: t('monthlyInspection:report.kpi.correctiveActions'),
        value: kpi?.correctiveActionCount ?? '-',
      },
    ]
  }, [report, t])

  const findingsByArea = useMemo(() => report?.findingsByArea ?? [], [report])
  const findingsByCategory = useMemo(
    () => report?.findingsByCategory ?? [],
    [report],
  )
  const findingGroups = report?.findingGroups ?? []
  const checklistGroups = report?.checklistGroups ?? []
  const approveList = report?.approveList ?? []

  const maxAreaCount = useMemo(
    () => Math.max(...findingsByArea.map((i) => i.findingCount), 1),
    [findingsByArea],
  )
  const maxCategoryCount = useMemo(
    () => Math.max(...findingsByCategory.map((i) => i.findingCount), 1),
    [findingsByCategory],
  )
  return (
    <Modal
      visible={visible}
      onCancel={onCancel}
      className={`${classPrefix}-modal`}
      title={
        <div className={`${classPrefix}-modal__header`}>
          <span>{t('common:btn.viewReport')}</span>
          <Button
            type='primary'
            icon={<IconShareExternal />}
            loading={exporting}
            disabled={exporting || reportLoading || !report}
            onClick={handleExport}
          >
            {t('common:btn.export')}
          </Button>
        </div>
      }
      maskClosable={false}
      autoFocus={false}
      focusLock={true}
      footer={null}
    >
      <Spin loading={reportLoading} block>
        <div
          className={classPrefix}
          ref={targetRef as React.RefObject<HTMLDivElement>}
        >
          {/* 顶部品牌栏 */}
          <div className={`${classPrefix}__topbar`}>
            <div className={`${classPrefix}__topbar-brand`}>
              <span>
                <LogoIcon width={135} height={33} />
              </span>
              <Divider type='vertical' style={{ height: '20px' }} />
              <span>
                <PdfExportIcon width={24} height={26} />
              </span>
              <span className={`${classPrefix}__topbar-text`}>
                {t('employeeViolations:export.brand')}
              </span>
            </div>
          </div>

          <div className={`${classPrefix}__page`}>
            <div className={`${classPrefix}__title`}>
              {t('monthlyInspection:report.title')}
            </div>

            {/* 报告元信息 */}
            <div className={`${classPrefix}__meta`}>
              <div className={`${classPrefix}__meta-item`}>
                <span className={`${classPrefix}__meta-label`}>
                  {t('monthlyInspection:columns.inspectionId')}
                </span>
                <span className={`${classPrefix}__meta-value`}>
                  {report?.code || '-'}
                </span>
              </div>
              <div className={`${classPrefix}__meta-item`}>
                <span className={`${classPrefix}__meta-label`}>
                  {t('monthlyInspection:report.meta.inspectionMonth')}
                </span>
                <span className={`${classPrefix}__meta-value`}>
                  {formatInspectionMonth(report?.inspectionDate)}
                </span>
              </div>
              <div className={`${classPrefix}__meta-item`}>
                <span className={`${classPrefix}__meta-label`}>
                  {t('monthlyInspection:columns.status')}
                </span>
                <span
                  className={`${classPrefix}__meta-value ${classPrefix}__meta-value--approved`}
                >
                  {t('common:auditFirmStatus.approved')}
                </span>
              </div>
              <div className={`${classPrefix}__meta-item`}>
                <span className={`${classPrefix}__meta-label`}>
                  {t('monthlyInspection:report.meta.startDateTime')}
                </span>
                <span className={`${classPrefix}__meta-value`}>
                  {report?.inspectionStartTime || '-'}
                </span>
              </div>
              <div className={`${classPrefix}__meta-item`}>
                <span className={`${classPrefix}__meta-label`}>
                  {t('monthlyInspection:report.meta.completeDateTime')}
                </span>
                <span className={`${classPrefix}__meta-value`}>
                  {report?.inspectionCompleteTime || '-'}
                </span>
              </div>
              <div className={`${classPrefix}__meta-item`}>
                <span className={`${classPrefix}__meta-label`}>
                  {t('monthlyInspection:submitModal.duration')}
                </span>
                <span className={`${classPrefix}__meta-value`}>
                  {formatDuration(report)}
                </span>
              </div>
              <div className={`${classPrefix}__meta-item`}>
                <span className={`${classPrefix}__meta-label`}>
                  {t('monthlyInspection:report.meta.inspectors')}
                </span>
                <span className={`${classPrefix}__meta-value`}>
                  {inspectorsText}
                </span>
              </div>
            </div>

            {/* INSPECTION SUMMARY */}
            <div className={`${classPrefix}__section-title`}>
              {t('monthlyInspection:report.sections.summary')}
            </div>

            <div className={`${classPrefix}__kpi-grid`}>
              <div className={`${classPrefix}__kpi-cards`}>
                {kpiCards.map((card) => (
                  <div key={card.label} className={`${classPrefix}__kpi-card`}>
                    <span className={`${classPrefix}__kpi-card-label`}>
                      {card.label}
                    </span>
                    <span
                      className={`${classPrefix}__kpi-card-value${
                        card.tone ? ` is-${card.tone}` : ''
                      }`}
                    >
                      {card.value}
                    </span>
                  </div>
                ))}
              </div>

              <div className={`${classPrefix}__kpi-area-card`}>
                <span className={`${classPrefix}__kpi-card-label`}>
                  {t('monthlyInspection:report.sections.findingsByArea')}
                </span>
                {findingsByArea.map((area) => (
                  <div key={area.type} className={`${classPrefix}__bar-row`}>
                    <div className={`${classPrefix}__bar-row-head`}>
                      <span className={`${classPrefix}__bar-row-label`}>
                        {formatAreaLabel(t, area.type) || '-'}
                      </span>
                      <span className={`${classPrefix}__bar-row-count`}>
                        {area.findingCount}
                      </span>
                    </div>
                    <div className={`${classPrefix}__bar-track`}>
                      <div
                        className={`${classPrefix}__bar-fill`}
                        style={{
                          width: `${(area.findingCount / maxAreaCount) * 100}%`,
                        }}
                      />
                    </div>
                  </div>
                ))}
              </div>
            </div>

            <div className={`${classPrefix}__kpi-category-card`}>
              <span className={`${classPrefix}__kpi-card-label`}>
                {t('monthlyInspection:report.sections.findingsByCategory')}
              </span>
              {findingsByCategory.map((category) => (
                <div
                  key={category.sectionId}
                  className={`${classPrefix}__category-row`}
                >
                  <span className={`${classPrefix}__category-label`}>
                    {handelFieldNameShow(
                      category.sectionName,
                      category.sectionNameAr,
                    )}
                  </span>
                  <div className={`${classPrefix}__bar-track`}>
                    <div
                      className={`${classPrefix}__bar-fill`}
                      style={{
                        width: `${
                          (category.findingCount / maxCategoryCount) * 100
                        }%`,
                      }}
                    />
                  </div>
                  <span className={`${classPrefix}__category-count`}>
                    {category.findingCount}
                  </span>
                </div>
              ))}
            </div>

            {/* FINDINGS & CORRECTIVE ACTIONS */}
            <div className={`${classPrefix}__section-title`}>
              {t('monthlyInspection:report.sections.findings')}
            </div>

            <table className={`${classPrefix}__table`}>
              <thead>
                <tr>
                  <th>
                    {t('monthlyInspection:report.table.nonCompliantItem')}
                  </th>
                  <th>{t('monthlyInspection:report.table.areaFloor')}</th>
                  <th>{t('monthlyInspection:report.table.finding')}</th>
                  <th>{t('monthlyInspection:report.table.responsibleDept')}</th>
                  <th>
                    {t('monthlyInspection:report.table.correctiveAction')}
                  </th>
                </tr>
              </thead>
              <tbody>
                {findingGroups.length > 0 ? (
                  findingGroups.map((group) =>
                    group.rows.map((row, rowIdx) => (
                      <tr key={`${group.itemId}-${rowIdx}`}>
                        {rowIdx === 0 && (
                          <td rowSpan={group.rows.length}>
                            {handelFieldNameShow(
                              group.itemName,
                              group.itemNameAr,
                            )}
                          </td>
                        )}
                        <td>{formatReportArea(t, row.type, row.floorCode)}</td>
                        <td>
                          {handelFieldNameShow(
                            row.findingRemark ?? '',
                            row.findingRemarkAr ?? '',
                          ) || '-'}
                        </td>
                        <td>
                          {handelFieldNameShow(
                            row.orgName ?? '',
                            row.orgNameAr ?? '',
                          ) || '-'}
                        </td>
                        <td>
                          {handelFieldNameShow(
                            row.correctiveAction ?? '',
                            row.correctiveActionAr ?? '',
                          ) || '-'}
                        </td>
                      </tr>
                    )),
                  )
                ) : (
                  <tr>
                    <td colSpan={5} className={`${classPrefix}__table-empty`}>
                      {t('monthlyInspection:report.table.noFindings')}
                    </td>
                  </tr>
                )}
              </tbody>
            </table>

            {/* CHECKLIST RESULTS */}
            <div className={`${classPrefix}__section-title`}>
              {t('monthlyInspection:report.sections.checklist')}
            </div>

            {checklistGroups.map((group) => (
              <div
                key={`${group.type}-${group.floorCode}`}
                className={`${classPrefix}__checklist`}
              >
                <div className={`${classPrefix}__checklist-group-title`}>
                  {formatChecklistGroupTitle(t, group)}
                </div>
                {group.sections.map((section) => (
                  <div key={section.sectionId}>
                    <div className={`${classPrefix}__checklist-section-title`}>
                      {handelFieldNameShow(
                        section.sectionName,
                        section.sectionNameAr,
                      ).toUpperCase()}
                    </div>
                    {section.items.map((item, itemIdx) => (
                      <div
                        key={`${item.itemId}-${itemIdx}`}
                        className={`${classPrefix}__checklist-item`}
                      >
                        <span className={`${classPrefix}__checklist-item-name`}>
                          {handelFieldNameShow(item.itemName, item.itemNameAr)}
                        </span>
                        <span
                          className={`${classPrefix}__answer-tag${
                            item.isSituation === IsSituationEnum.Yes
                              ? ' is-yes'
                              : item.isSituation === IsSituationEnum.No
                                ? ' is-no'
                                : ''
                          }`}
                        >
                          <span className={`${classPrefix}__tag-text`}>
                            {item.isSituation === IsSituationEnum.Yes
                              ? t('common:yes')
                              : item.isSituation === IsSituationEnum.No
                                ? t('common:no')
                                : t('monthlyInspection:form.na')}
                          </span>
                        </span>
                        <span
                          className={`${classPrefix}__checklist-item-findings`}
                        >
                          {t('monthlyInspection:report.findingsCount', {
                            count: item.findingCount,
                          })}
                        </span>
                      </div>
                    ))}
                  </div>
                ))}
              </div>
            ))}

            {/* APPROVAL & SIGN-OFF */}
            <div className={`${classPrefix}__section-title`}>
              {t('monthlyInspection:report.sections.approval')}
            </div>

            <div className={`${classPrefix}__approval`}>
              {approveList.map((node, nodeIdx) => (
                <div key={node.id} className={`${classPrefix}__approval-node`}>
                  <div className={`${classPrefix}__approval-line`}>
                    <span className={`${classPrefix}__approval-dot`} />
                    {nodeIdx < approveList.length - 1 && (
                      <span className={`${classPrefix}__approval-track`} />
                    )}
                  </div>
                  <div className={`${classPrefix}__approval-content`}>
                    <div className={`${classPrefix}__approval-head`}>
                      <span className={`${classPrefix}__approval-title`}>
                        {node.approveStatus === approveActionTypeEnum.Submit
                          ? t('monthlyInspection:report.submitted')
                          : t('monthlyInspection:timeLine.hsManagerApproval')}
                      </span>
                      <span className={`${classPrefix}__approval-time`}>
                        {node.operTime ?? ''}
                      </span>
                    </div>
                    <div className={`${classPrefix}__approval-user`}>
                      <span className={`${classPrefix}__approval-user-chip`}>
                        <UserHead size={20} />
                        <span className={`${classPrefix}__tag-text`}>
                          {handelFieldNameShow(
                            node.operUserName ?? '',
                            node.operUserNameAr ?? '',
                          ) || '-'}
                        </span>
                      </span>
                      {node.approvalResult != null && (
                        <span
                          className={`${classPrefix}__status-tag is-${
                            node.approvalResult === approvalResultEnum.ApproveOk
                              ? 'approved'
                              : 'rejected'
                          }`}
                        >
                          <span className={`${classPrefix}__tag-text`}>
                            {node.approvalResult ===
                            approvalResultEnum.ApproveOk
                              ? t('monthlyInspection:timeLine.approved')
                              : t('monthlyInspection:timeLine.rejected')}
                          </span>
                        </span>
                      )}
                    </div>
                    {node.comments && (
                      <div className={`${classPrefix}__approval-comment`}>
                        {node.comments}
                      </div>
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </Spin>
    </Modal>
  )
}

