import { Button, Table, Grid, Input, Link } from '@arco-design/web-react'
import { useState, useEffect } from 'react'
import { useTranslation } from 'react-i18next'
import ApprovalProgressCard from '@common/components/ApprovalProgressCard'
import {
  IncidentReportStep,
  IncidentReportApproval,
  PROPERTY_TYPE_I18N_KEYS,
  type PropertyTypeEnum,
} from '@/constants/incidentReport'
import { useLocation, useNavigate, useParams } from 'react-router-dom'
import ExportPDF from './PDFExport'
import { usePDFExport } from '../../hooks/usePDFExport'
import { renderEllipsisText } from '@common/components/EllipsisText'
import {
  incidentReportDetail,
  getApprovalDetail,
  incidentReportReject,
  incidentReportApproval,
} from '@/service'
import { useRequest } from 'ahooks'
import { LanguageEnum } from '@common/constants/language'
import { getLanguage } from '@common/utils/localStorage'
import { handelFieldNameShow } from '@/utils/tools'
import ShieldAddIcon from '@/assets/images/icon/shield-add-icon.svg?react'
import AmbulanceIcon from '@/assets/images/icon/first-aid-kit-icon.svg?react'
import FireDepartmentIcon from '@/assets/images/icon/fire-extinguisher-icon.svg?react'
import MoreFourIcon from '@/assets/images/icon/more-four-icon.svg?react'
import UserIcon from '@/assets/images/icon/user-icon.svg?react'
import PalaceIcon from '@/assets/images/icon/palace-icon.svg?react'
import './index.less'

const { Row, Col } = Grid
const TextArea = Input.TextArea

// partyType: 1=Police, 2=Ambulance, 3=Fire Department, 4=Others
const PARTY_TYPE_MAP: Record<number, { icon: React.ReactNode; label: string }> =
  {
    1: { icon: <ShieldAddIcon />, label: 'Police' },
    2: { icon: <AmbulanceIcon />, label: 'Ambulance' },
    3: { icon: <FireDepartmentIcon />, label: 'Fire Department' },
    4: { icon: <MoreFourIcon />, label: 'Others' },
  }

// ─── Small helpers ─────────────────────────────────────────────────────────────
const renderAttachments = (list: any[]) => {
  if (!list?.length) return null
  return (
    <div className='attachment'>
      {list.map((item: any, index: number) => (
        <div className='item' key={index}>
          <img
            src={item.absUrl}
            alt=''
            style={{ width: '100%', height: '100%' }}
          />
        </div>
      ))}
    </div>
  )
}

const InfoRow = ({
  label,
  children,
}: {
  label: string
  children: React.ReactNode
}) => (
  <div className='info'>
    <div className='label'>{label}</div>
    <div className='value'>{children}</div>
  </div>
)

// ─── Main component ────────────────────────────────────────────────────────────
const IncidentReportDetail = ({ current, userList, setShowStatus }: any) => {
  const { t } = useTranslation(['common', 'incidentReport'])
  const isLanguageAR = getLanguage() === LanguageEnum.AR
  const navigate = useNavigate()
  const { id } = useParams()
  const location = useLocation()

  const [infoData, setInfoData] = useState<any>({})
  const [approveLog, setApproveLog] = useState<any>([])
  const [approveFlag, setApproveFlag] = useState<number>(0)
  const [approvalStatus, setApprovalStatus] = useState<any>(null)
  const [comment, setComment] = useState('')

  const backUrl = `/incident-report/incident-report-management/list`
  const isApproval = current === IncidentReportStep.StepThree

  const { targetRef, exportToPDF } = usePDFExport({
    filename: 'incident_report',
    scale: 2,
    orientation: 'p',
    format: 'a4',
    singlePage: true,
  })

  // ── API ──
  const {
    loading: getIncidentReportDetailLoading,
    run: getIncidentReportDetail,
  } = useRequest(incidentReportDetail, {
    manual: true,
    onSuccess: (res: any) => {
      setInfoData(res)
      setShowStatus(res?.status)
      setApprovalStatus(res?.status)
    },
  })

  const { run: runGetApprovalDetail } = useRequest(getApprovalDetail, {
    manual: true,
    onSuccess: (res: any) => {
      setApproveLog(res?.approveList || [])
      setApproveFlag(res?.approveFlag)
    },
  })

  const { run: runReject, loading: rejectLoading } = useRequest(
    incidentReportReject,
    {
      manual: true,
      onSuccess: () => {
        navigate(
          `/incident-report/incident-report-management/addOrEdit/4/${id}`,
        )
      },
    },
  )

  const { run: runApprove, loading: approveLoading } = useRequest(
    incidentReportApproval,
    {
      manual: true,
      onSuccess: () => {
        navigate(
          `/incident-report/incident-report-management/addOrEdit/4/${id}`,
        )
      },
    },
  )

  useEffect(() => {
    if (id) {
      getIncidentReportDetail({ incidentReportId: id })
      runGetApprovalDetail({ incidentReportId: id })
    }
  }, [id])

  const handelBack = () => navigate(backUrl)

  const handleReject = () => {
    runReject({ incidentReportId: id, rejectReason: comment })
  }

  const handleApprove = () => {
    runApprove({ incidentReportId: id })
  }

  const [exportLoading, setExportLoading] = useState(false)

  const exportAsPdf = async () => {
    if (exportLoading) return
    setExportLoading(true)
    try {
      await exportToPDF()
    } catch (error) {
      console.error('PDF export failed:', error)
    } finally {
      setExportLoading(false)
    }
  }

  // ── Computed values ──
  const emergencyLocationText =
    infoData?.locationType === 1
      ? t('incidentReport:form.insideBuilding')
      : infoData?.locationType === 0
        ? t('incidentReport:form.outOfBuilding')
        : '—'

  const floorText = Array.isArray(infoData?.floors)
    ? infoData.floors.join(', ')
    : ''
  const employeeTableData =
    infoData?.employees?.map((item: any, index: number) => ({
      ...item,
      key: index,
    })) || []

  const employeeColumns = [
    {
      title: t('incidentReport:table.name'),
      dataIndex: 'userId',
      render: (_: any, record: any) => {
        const name = userList?.find(
          (u: any) => u?.value == record?.userId || u?.userId == record?.userId,
        )?.label
        return renderEllipsisText(name)
      },
    },
    {
      title: t('incidentReport:table.titleSynced'),
      dataIndex: 'title',
      render: (_, record) => {
        return record?.title
      },
    },
    {
      title: t('incidentReport:table.natureOfInjury'),
      dataIndex: 'natureOfInjury',
      render: (_: any, record: any) =>
        renderEllipsisText(
          handelFieldNameShow(record?.natureOfInjury, record?.natureOfInjuryAr),
        ),
    },
  ]

  const propertyColumns = [
    {
      title: t('incidentReport:table.propertyType'),
      dataIndex: 'propertyType',
      render: (value: PropertyTypeEnum | null) =>
        renderEllipsisText(
          value != null && PROPERTY_TYPE_I18N_KEYS[value]
            ? t(PROPERTY_TYPE_I18N_KEYS[value])
            : '—',
        ),
    },
    {
      title: t('incidentReport:table.propertyName'),
      dataIndex: 'propertyName',
      render: (_: any, record: any) =>
        renderEllipsisText(
          handelFieldNameShow(record?.propertyName, record?.propertyNameAr),
        ),
    },
    {
      title: t('incidentReport:table.natureOfDamage'),
      dataIndex: 'natureOfDamage',
      render: (_: any, record: any) =>
        renderEllipsisText(
          handelFieldNameShow(record?.natureOfDamage, record?.natureOfDamageAr),
        ),
    },
  ]

  return (
    <div className='incidentReportDetail'>
      <div className='incidentReportDetail-top'>
        <div className='incidentReportDetail-top-left'>
          {/* ─ Incident meta bar ─ */}
          <div className='incident-meta-bar'>
            <span className='meta-label'>{t('incidentReport:incidentId')}</span>
            <span className='meta-value'>{infoData?.incidentCode || '—'}</span>
            {infoData?.relatedEmergencyId && (
              <>
                {/* // */}
                <span className='meta-sep'>|</span>
                <span className='meta-label'>
                  {t('incidentReport:relatedEmergencyResponse') ||
                    'Related Emergency Response'}
                </span>
                <Link
                  className='meta-link'
                  onClick={() =>
                    navigate(
                      `/emergency-response/emergency-response-activation/detail/${infoData?.relatedEmergencyId}/active`,
                    )
                  }
                >
                  {infoData.relatedEmergencyCode || infoData.relatedEmergencyId}
                </Link>
              </>
            )}
          </div>

          {/* ─── BASIC INFORMATION ─── */}
          <div className='section-header'>
            {t('incidentReport:section.basicInformation')}
          </div>
          <Row>
            <Col span={12}>
              <InfoRow label={t('incidentReport:columns.incidentDateTime')}>
                {
                  // handelFieldNameShow(
                  infoData?.incidentDate || '—'
                }
              </InfoRow>
            </Col>
            <Col span={12}>
              <InfoRow label={t('incidentReport:form.emergencyLocation')}>
                {emergencyLocationText}
              </InfoRow>
            </Col>
            {infoData?.locationType === 1 && floorText && (
              <Col span={24}>
                <InfoRow label={t('incidentReport:form.floorOfEmergency')}>
                  {floorText}
                </InfoRow>
              </Col>
            )}
            <Col span={24}>
              <InfoRow label={t('incidentReport:columns.incidentDetails')}>
                {handelFieldNameShow(
                  infoData?.incidentDetails,
                  infoData?.incidentDetailsAr,
                ) || '—'}
              </InfoRow>
            </Col>
            <Col span={24}>
              <InfoRow label={t('incidentReport:section.actionsTaken')}>
                {handelFieldNameShow(
                  infoData?.actionsTaken,
                  infoData?.actionsTakenAr,
                ) || '—'}
              </InfoRow>
            </Col>
            {infoData?.attachmentList?.length > 0 && (
              <Col span={24}>
                <div className='info'>
                  <div className='label'>
                    {t('incidentReport:form.attachment')}
                  </div>
                  {renderAttachments(infoData?.attachmentList)}
                </div>
              </Col>
            )}
          </Row>

          {/* ─── EXTERNAL PARTY INVOLVED ─── */}
          <div className='section-header'>
            {t('incidentReport:section.externalPartyInvolved')}
          </div>
          <div className='info'>
            <div className='label'>
              {t('incidentReport:form.externalPartyInvolved')}
            </div>
            <div className='value'>
              <div className='incidentDom-readonly'>
                <div
                  className={`incidentDom-readonly__btn${infoData?.externalPartyInvolved === 1 ? ' incidentDom-readonly__btn--active' : ''}`}
                >
                  {t('common:yes')}
                </div>
                <div
                  className={`incidentDom-readonly__btn${infoData?.externalPartyInvolved === 2 ? ' incidentDom-readonly__btn--active' : ''}`}
                >
                  {t('common:no')}
                </div>
              </div>
            </div>
          </div>
          {infoData?.externalPartyInvolved === 1 &&
            (infoData?.externalParties || []).map((party: any) => {
              const meta = PARTY_TYPE_MAP[party.partyType]
              const hasContent =
                party.responseDetailsEn ||
                party.responseDetailsAr ||
                party.attachmentList?.length

              return (
                <div key={party.id} className={`party-block party-block-${party.partyType}`}>
                  <div className='party-block-header'>
                    <span className='party-block-header__icon'>
                      {meta.icon}
                    </span>
                    <span className='party-block-header__label'>
                      {meta.label}
                    </span>
                  </div>
                  {hasContent && (
                    <div className='party-block-content'>
                      {(party.responseDetailsEn || party.responseDetailsAr) && (
                        <InfoRow
                          label={t('incidentReport:form.responseDetails')}
                        >
                          {handelFieldNameShow(
                            party.responseDetailsEn,
                            party.responseDetailsAr,
                          )}
                        </InfoRow>
                      )}
                      {party.attachmentList?.length > 0 && (
                        <div className='info'>
                          <div className='label'>
                            {t('incidentReport:form.attachment')}
                          </div>
                          {renderAttachments(party.attachmentList)}
                        </div>
                      )}
                    </div>
                  )}
                </div>
              )
            })}

          {/* ─── IMPACT ─── */}
          <div className='section-header'>
            {t('incidentReport:section.impact')}
          </div>

          {/* Employee Impacted */}
          {employeeTableData.length > 0 && (
            <div className='impact-block impact-block-1'>
              <div className='impact-block-header'>
                <span className='impact-block-header__icon'>
                  <UserIcon />
                </span>
                <span>{t('incidentReport:section.employeeImpacted')}</span>
              </div>
              <div className='impact-block-content'>
                <Table
                  rowKey='key'
                  className={'table'}
                  columns={employeeColumns}
                  data={employeeTableData}
                  scroll={{ y: 300 }}
                  pagination={false}
                  borderCell
                />
              </div>
            </div>
          )}

          {/* Property Impacted */}
          {infoData?.properties?.length > 0 && (
            <div className='impact-block impact-block-2'>
              <div className='impact-block-header'>
                <span className='impact-block-header__icon'>
                  <PalaceIcon />
                </span>
                <span>{t('incidentReport:section.propertyImpacted')}</span>
              </div>
              <div className='impact-block-content'>
                <Table
                  rowKey='propertyImpactedId'
                  className={'table'}
                  columns={propertyColumns}
                  data={infoData.properties}
                  scroll={{ y: 300 }}
                  pagination={false}
                  borderCell
                />
              </div>
            </div>
          )}

          {/* Other Impact */}
          {(infoData?.otherImpactAr || infoData?.otherImpact) && (
            <InfoRow label={t('incidentReport:section.otherImpact')}>
              {isLanguageAR ? infoData.otherImpactAr : infoData.otherImpact}
            </InfoRow>
          )}

          {/* ─── ISSUES IDENTIFIED ─── */}
          {infoData?.issues?.length > 0 && (
            <>
              <div className='section-header'>
                {t('incidentReport:section.issuesIdentified')}
              </div>
              {infoData.issues.map((issue: any, index: number) => {
                return (
                  <div key={issue.id ?? index} className='issue-item'>
                    <div className='issue-item-header'>
                      <span className='issue-item-header__title'>
                        {t('incidentReport:issueLabel', { num: index + 1 })}
                      </span>
                    </div>
                    <InfoRow label={t('incidentReport:form.notesRemarks')}>
                      {handelFieldNameShow(
                        issue.notesRemarksEn,
                        issue.notesRemarksAr,
                      ) || '—'}
                    </InfoRow>
                    {issue.attachmentList?.length > 0 && (
                      <div className='info'>
                        <div className='label'>
                          {t('incidentReport:form.attachment')}
                        </div>
                        {renderAttachments(issue.attachmentList)}
                      </div>
                    )}
                    <InfoRow label={t('incidentReport:form.correctiveActions')}>
                      {handelFieldNameShow(
                        issue.correctiveActionEn,
                        issue.correctiveActionAr,
                      ) || '—'}
                    </InfoRow>
                    <Row>
                      <Col span={12}>
                        <InfoRow
                          label={t('incidentReport:form.responsibleDepartment')}
                        >
                          {issue.responsibleOrgId || '—'}
                        </InfoRow>
                      </Col>
                      <Col span={12}>
                        <InfoRow
                          label={t('incidentReport:form.targetClosureDate')}
                        >
                          {issue.targetClosureDate || '—'}
                        </InfoRow>
                      </Col>
                    </Row>
                  </div>
                )
              })}
            </>
          )}
        </div>
        {/* ─ Right panel ─ */}
        <div className='incidentReportDetail-top-right'>
          <ApprovalProgressCard
            title={t('incidentReport:progress.title')}
            approvalRejected={incidentReportReject}
            approvalApproved={incidentReportApproval}
            type={'incident'}
            approveLog={approveLog}
            approveFlag={isApproval ? approveFlag : 0}
            backUrl={backUrl}
            moduleId={id}
            moduleIdKey={'incidentReportId'}
          />
        </div>
      </div>
      {current == IncidentReportStep.StepFour && (
        <div className='incidentReportDetail-bottom'>
          <Button className='footer__btn' onClick={handelBack}>
            {t('common:btn.back')}
          </Button>
          {approvalStatus === IncidentReportApproval.Approved && (
            <Button
              className='footer__btn'
              type='primary'
              loading={exportLoading}
              disabled={exportLoading}
              onClick={exportAsPdf}
            >
              {t('incidentReport:btn.exportAsPdf')}
            </Button>
          )}
          {approvalStatus === IncidentReportApproval.Rejected && (
            <Button
              className='footer__btn'
              type='primary'
              onClick={() =>
                navigate(
                  `/incident-report/incident-report-management/addOrEdit/2/${id}`,
                )
              }
            >
              {t('common:btn.edit')}
            </Button>
          )}
        </div>
      )}

      <div className='exportPDF-box'>
        <ExportPDF
          targetRef={targetRef}
          infoData={infoData}
          userList={userList}
          isLanguageAR={isLanguageAR}
          approveLog={approveLog}
        />
      </div>
    </div>
  )
}

export default IncidentReportDetail

import { Button, Form, Input, Message } from '@arco-design/web-react'
import { useRequest } from 'ahooks'
import { useNavigate } from 'react-router-dom'
import { appThemeName } from '@common/constants/env'
import { AppThemeName } from '@common/constants/app'
import IconOrga from '@common/assets/images/logo/orga-logo.svg?react'
import IconOrgu from '@common/assets/images/logo/logo.orgu.svg?react'
import { sendResetPasswordEmail } from '@/service'
import { encode } from '@common/utils/crypto'
import { useTranslation } from 'react-i18next'
import './LoginForm.less'

const FormItem = Form.Item
const classPrefix = 'contractor-login'

const ForgotPasswordForm = () => {
  const { t } = useTranslation(['common', 'incidentReport'])
  const [form] = Form.useForm()
  const navigate = useNavigate()

  const { loading, run: sendResetLink } = useRequest(sendResetPasswordEmail, {
    manual: true,
    onSuccess(res) {
      Message.success('Reset link sent successfully. Please check your email.')
    },
    onError(e: any) {
      form.setFields({
        mail: {
          error: { message: e.message || 'Failed to send reset link' },
        },
      })
    },
  })

  const handleSubmit = (values: { mail: string }) => {
    sendResetLink({ mail: encode(values?.mail, 'verify') })
  }

  return (
    <div className={classPrefix}>
      <div className={`${classPrefix}__card`}>
        <h1 className={`${classPrefix}__title`}>Reset Password</h1>
        <p className={`${classPrefix}__subtitle`}>
          If the email exists in our system, we will send an email with a link
          to reset your password
        </p>
        <Form
          form={form}
          autoComplete='off'
          layout='vertical'
          size='large'
          onSubmit={handleSubmit}
        >
          <FormItem
            label='Email'
            field='mail'
            rules={[{ required: true, message: 'Please enter your email' }]}
          >
            <Input placeholder='Please enter' />
          </FormItem>
          <FormItem className={`${classPrefix}__btn-item`}>
            <div className={`${classPrefix}__btn-row`}>
              <Button
                type='outline'
                long
                onClick={() => navigate('/contractor-login')}
