import { Button, Form, Input, Message, Tooltip } from '@arco-design/web-react'
import { IconQuestionCircle } from '@arco-design/web-react/icon'
import { useRequest } from 'ahooks'
import { useNavigate, useSearchParams } from 'react-router-dom'
import { appThemeName } from '@common/constants/env'
import { AppThemeName } from '@common/constants/app'
import IconOrga from '@common/assets/images/logo/orga-logo.svg?react'
import IconOrgu from '@common/assets/images/logo/logo.orgu.svg?react'
import { contractorResetPassword } from '@/service'
import { encode } from '@common/utils/crypto'
import './LoginForm.less'

const FormItem = Form.Item
const classPrefix = 'contractor-login'

const PASSWORD_SPECIAL_CHARS = '~_!@#$%^&*'
const PASSWORD_REGEX_SPECIAL = /[~_!@#$%^&*]/

const passwordTooltipContent = (
  <ul style={{ margin: 0, paddingLeft: 16, fontSize: 12, lineHeight: 1.8 }}>
    <li>Length from 8 to 16 characters</li>
    <li>
      At least one uppercase letter and one number, and at least one special
      character, including {PASSWORD_SPECIAL_CHARS}
    </li>
    <li>Spaces are not allowed</li>
  </ul>
)

const validatePassword = (value: string, callback: (msg?: string) => void) => {
  if (!value) return callback('Please enter your new password')
  if (value.length < 8 || value.length > 16)
    return callback('Password must be 8–16 characters')
  if (!/[A-Z]/.test(value))
    return callback('Must contain at least one uppercase letter')
  if (!/[0-9]/.test(value)) return callback('Must contain at least one number')
  if (!PASSWORD_REGEX_SPECIAL.test(value))
    return callback(
      `Must contain at least one special character (${PASSWORD_SPECIAL_CHARS})`,
    )
  if (/\s/.test(value)) return callback('Spaces are not allowed')
  callback()
}

const newPasswordLabel = (
  <span style={{ display: 'inline-flex', alignItems: 'center', gap: 4 }}>
    New Password
    <Tooltip content={passwordTooltipContent} position='top'>
      <IconQuestionCircle
        style={{ color: '#86909c', cursor: 'pointer', fontSize: 14 }}
      />
    </Tooltip>
  </span>
)

const ResetPasswordForm = () => {
  const [form] = Form.useForm()
  const navigate = useNavigate()
  const [searchParams] = useSearchParams()
  const token = searchParams.get('token') || searchParams.get('resetToken') || ''

  const { loading, run: resetPassword } = useRequest(contractorResetPassword, {
    manual: true,
    onSuccess() {
      Message.success('Password has been reset. Please sign in.')
      navigate('/contractor-login/reset-password-success')
    },
    onError(e: any) {
      Message.error(e.message || 'Failed to reset password')
    },
  })

  const handleSubmit = (values: {
    newPassword: string
    confirmPassword: string
  }) => {
    resetPassword({
      password: encode(values.newPassword, 'verify'),
      resetToken: token,
    })
  }

  return (
    <div className={classPrefix}>
      <div className={`${classPrefix}__card`}>
        <h1 className={`${classPrefix}__title`}>Set a login password</h1>
        <p className={`${classPrefix}__subtitle`}>
          Enter your new password below.
        </p>
        <Form
          form={form}
          autoComplete='off'
          layout='vertical'
          size='large'
          onSubmit={handleSubmit}
        >
          <FormItem
            label={newPasswordLabel}
            field='newPassword'
            rules={[
              {
                validator: (value, callback) =>
                  validatePassword(value, callback),
              },
            ]}
          >
            <Input.Password placeholder='Please enter' />
          </FormItem>
          <FormItem
            className={`${classPrefix}__password-item`}
            label='Confirm Password'
            field='confirmPassword'
            rules={[
              { required: true, message: 'Please confirm your password' },
              {
                validator: (value, callback) => {
                  if (value !== form.getFieldValue('newPassword')) {
                    callback('Passwords do not match')
                  } else {
                    callback()
                  }
                },
              },
            ]}
          >
            <Input.Password placeholder='Please enter' />
          </FormItem>
          <FormItem className={`${classPrefix}__btn-item`}>
            <Button type='primary' htmlType='submit' long loading={loading}>
              Reset Password
            </Button>
          </FormItem>
        </Form>
      </div>
      <div className={`${classPrefix}__logo`}>
        {appThemeName === AppThemeName.OrgA ? <IconOrga /> : <IconOrgu />}
      </div>
    </div>
  )
}

export default ResetPasswordForm

